    @Test
    @Order(20)
    void putLargeObject() {
        // 22 MB – exceeds the old Jackson 20 MB maxStringLength default
        byte[] largeBody = new byte[22 * 1024 * 1024];
        Arrays.fill(largeBody, (byte) 'A');

        given()
        .when()
            .put("/large-object-bucket")
        .then()
            .statusCode(200);

        given()
            .contentType("application/octet-stream")
            .body(largeBody)
