            .statusCode(200)
            .header("ETag", notNullValue());

        given()
        .when()
            .get("/large-object-bucket/large-file.bin")
        .then()
            .statusCode(200)
            .header("Content-Length", String.valueOf(largeBody.length));

        given().delete("/large-object-bucket/large-file.bin");
        given().delete("/large-object-bucket");
    }
